import { createRequire } from "module"
import { dirname, resolve } from "path"
import { fileURLToPath } from "url"
import {
  RpcProvider, Account, hash, stark, CallData, SignerInterface,
  transaction, EDAMode,
} from "../apps/demo/node_modules/starknet/dist/index.mjs"

